import 'proxy_policy.dart';

class RequestMetadata {
  const RequestMetadata({
    required this.remoteAddress,
    required this.scheme,
    required this.host,
    this.headers = const <String, String>{},
  });

  final String remoteAddress;
  final String scheme;
  final String host;
  final Map<String, String> headers;

  String? header(String name) => headers[name.toLowerCase()];
}

class ResolvedOrigin {
  const ResolvedOrigin({
    required this.scheme,
    required this.host,
    required this.clientAddress,
  });

  final String scheme;
  final String host;
  final String clientAddress;

  Uri uri(String path) => Uri.parse('$scheme://$host$path');
}

class ExternalOriginResolver {
  ExternalOriginResolver(this.policy);

  final TrustedProxyPolicy policy;

  ResolvedOrigin resolve(RequestMetadata request) {
    if (!policy.trusts(request.remoteAddress)) {
      return ResolvedOrigin(
        scheme: request.scheme,
        host: request.host,
        clientAddress: request.remoteAddress,
      );
    }

    final forwardedFor = _values(request.header('x-forwarded-for'));
    final forwardedProto = _values(request.header('x-forwarded-proto'));
    final forwardedHost = _values(request.header('x-forwarded-host'));

    return ResolvedOrigin(
      scheme: forwardedProto.isEmpty ? request.scheme : forwardedProto.first,
      host: forwardedHost.isEmpty ? request.host : forwardedHost.first,
      clientAddress:
          forwardedFor.isEmpty ? request.remoteAddress : forwardedFor.first,
    );
  }

  List<String> _values(String? value) {
    if (value == null || value.trim().isEmpty) return const <String>[];
    return value.split(',').map((part) => part.trim()).toList();
  }
}

