import '../lib/proxy_policy.dart';
import '../lib/request_origin.dart';

void check(bool condition, String message) {
  if (!condition) throw StateError(message);
}

void main() {
  final policy = TrustedProxyPolicy(['10.20.0.7']);
  check(policy.trusts('10.20.0.7'), 'an exact proxy address is trusted');
  check(!policy.trusts('10.20.0.8'), 'an unlisted address is not trusted');

  final resolver = ExternalOriginResolver(policy);
  final direct = resolver.resolve(const RequestMetadata(
    remoteAddress: '198.51.100.24',
    scheme: 'http',
    host: 'worker.internal',
    headers: {
      'x-forwarded-for': '203.0.113.9',
      'x-forwarded-proto': 'https',
      'x-forwarded-host': 'ignored.example',
    },
  ));
  check(direct.scheme == 'http', 'untrusted senders cannot replace the scheme');
  check(direct.host == 'worker.internal', 'untrusted senders cannot replace the host');
  check(direct.clientAddress == '198.51.100.24', 'the direct peer is retained');

  final proxied = resolver.resolve(const RequestMetadata(
    remoteAddress: '10.20.0.7',
    scheme: 'http',
    host: 'worker.internal',
    headers: {
      'x-forwarded-for': '203.0.113.12',
      'x-forwarded-proto': 'https',
      'x-forwarded-host': 'hooks.example.test',
    },
  ));
  check(proxied.uri('/ready').toString() ==
      'https://hooks.example.test/ready', 'a trusted one-hop proxy sets the origin');
  check(proxied.clientAddress == '203.0.113.12', 'one-hop client is resolved');
}
